// HMAC-SHA256 verify of X-Webhook-Signature header against raw body.
// REDACTED: set SECRET to the same value as the Cloudflare Pages secret N8N_WEBHOOK_SECRET.
const crypto = require('crypto');
const SECRET = 'REPLACE_WITH_N8N_WEBHOOK_SECRET';

const headers = $input.first().json.headers || {};
const signature = headers['x-webhook-signature'] || headers['X-Webhook-Signature'] || '';
const rawBody = $input.first().json.body;
const bodyString = typeof rawBody === 'string' ? rawBody : JSON.stringify(rawBody);

if (!SECRET) {
  return [{ json: { ...JSON.parse(bodyString), _hmacSkipped: true } }];
}

if (!signature) {
  throw new Error('Missing X-Webhook-Signature header');
}

const expected = crypto.createHmac('sha256', SECRET).update(bodyString).digest('hex');
const valid = crypto.timingSafeEqual(
  Buffer.from(signature, 'hex'),
  Buffer.from(expected, 'hex')
);

if (!valid) {
  throw new Error('Invalid HMAC signature');
}

return [{ json: JSON.parse(bodyString) }];
